// Helper: Convert a hex string (with or without spaces) to a byte array
function hexStringToByteArray(hexString) {
    // Remove any whitespace
    hexString = hexString.replace(/\s+/g, '');
    let result = [];
    // Process every two characters as a byte
    for (let i = 0; i < hexString.length; i += 2) {
        result.push(parseInt(hexString.substr(i, 2), 16));
    }
    return result;
}

// Helper: Convert a 4-byte array to a decimal serial number
function toDecimalSN(byteArray) {
    return byteArray.reduce((acc, byte, index) => acc + (byte << ((3 - index) * 8)), 0);
}

function parseReturnPayload(data) {
    // If data is a string, assume it’s a hex string and convert it to a byte array.
    if (typeof data === 'string') {
        data = hexStringToByteArray(data);
    } else if (!Array.isArray(data)) {
        data = Array.from(data);
    }

    // Parse header, length, and command
    const header = data[0];
    const length = (data[1] << 8) + data[2]; // big-endian conversion
    const command = data[3];

    // Parse fields specific to the return payload (14-byte message format)
    const movementAddress = data[4];  // e.g., 0x20 means movement 2
    const hole = data[5];             // Hole position
    const area = data[6];             // Area code

    // Charging treasure SN: bytes 7-10
    const snBytes = data.slice(7, 11);
    const sn = toDecimalSN(snBytes);

    const returnStatus = data[11];    // e.g., 0x01 means return successful
    const softwareVersion = data[12]; // e.g., 0x04 might indicate version V004
    const checksum = data[13];

    return {
        header,
        length,
        command,
        movementAddress,
        hole,
        area,
        sn,
        returnStatus,
        softwareVersion,
        checksum
    };
}

// Parse the incoming payload and update msg.payload
msg.payload = parseReturnPayload(msg.payload);
return msg;

