function parsePopupSNPayload(data) {
    // Convert hex string to byte array if necessary
    if (typeof data === 'string') {
        data = hexStringToByteArray(data);
    } else if (!Array.isArray(data)) {
        data = Array.from(data);
    }

    // Parse the header, length, and command fields
    const header = data[0];
    const length = (data[1] << 8) + data[2];  // Big-endian
    const command = data[3];
    const movementAddress = data[4];

    // Battery SN is in bytes 5-8
    const snBytes = data.slice(5, 9);
    const batterySN = toDecimalSN(snBytes);

    // Exit status and solenoid status
    const exitStatus = data[9];
    const solenoidStatus = data[10];

    // If there's an extra field (e.g., calibration or checksum), include it
    let calibration = null;
    if (data.length > 11) {
        calibration = data[11];
    }

    return {
        header,
        length,
        command,
        movementAddress,
        batterySN,
        exitStatus,
        solenoidStatus,
        calibration
    };
}

// Parse the incoming payload and update msg.payload
msg.payload = parsePopupSNPayload(msg.payload);
return msg;

