    msg.topic = 'CSTA/post/' + stationId;
    return msg;
}

const pricing = station.pricing && typeof station.pricing === 'object'
    ? station.pricing
    : {};

const hardware = {
    gateway: station?.hardware?.gateway ?? null,
    gatewayoptions: station?.hardware?.gatewayoptions ?? null
};

const formoptions = normalizeOptionGroup(station.formoptions);
const marketingoptions = normalizeOptionGroup(station.marketingoptions);
const analyticsoptions = normalizeOptionGroup(station.analyticsoptions);

const modules = Array.isArray(station.modules) ? station.modules : [];
const freshModuleIndexes = new Set();
let recentModuleFound = false;

modules.forEach((mod, modIndex) => {
    const moduleTime = new Date(mod?.lastUpdated).getTime();
    if (Number.isFinite(moduleTime) && (now - moduleTime) < freshAfterMs) {
        freshModuleIndexes.add(modIndex);
        recentModuleFound = true;
    }
});

let finalSNs = [];
let firstModuleId = null;
let vendBatteryCandidate = null;

const vendSlotStr = String(station.vendslot || '0.1');
const vendParts = vendSlotStr.split('.');
const vendModuleIndex = parseInt(vendParts[0], 10);
const vendSlotNumber = parseInt(vendParts[1], 10);

const globalSlots = [];
const globalIndexBySlot = new Map();

modules.forEach((stationModule, modIndex) => {
    const slots = Array.isArray(stationModule?.slots) ? stationModule.slots : [];
    slots.forEach((slot) => {
        const slotPosition = Number(slot?.position);
        const key = modIndex + ':' + slotPosition;
        globalIndexBySlot.set(key, globalSlots.length);
        globalSlots.push({
            modIndex,
            slotPosition
        });
    });
});

globalSlots.sort((left, right) => {
    if (left.modIndex === right.modIndex) {
        return left.slotPosition - right.slotPosition;
    }
    return left.modIndex - right.modIndex;
});

globalSlots.forEach((slot, index) => {
    globalIndexBySlot.set(slot.modIndex + ':' + slot.slotPosition, index);
});

let vendIndex = globalSlots.findIndex((slot) =>
    slot.modIndex === vendModuleIndex && slot.slotPosition === vendSlotNumber
);
if (vendIndex === -1) vendIndex = 0;

const totalSlots = globalSlots.length;
let qualifyingSlots = [];

modules.forEach((stationModule, modIndex) => {
    if (!freshModuleIndexes.has(modIndex)) {
        return;
    }

    const slots = Array.isArray(stationModule?.slots) ? stationModule.slots : [];
    slots.forEach((slot) => {
        const sn = Number(slot?.sn || 0);
        const batteryLevel = Number(slot?.batteryLevel || 0);
        if (Number(slot?.status) !== 1) return;
        if (batteryLevel < 80) return;
        if (!sn || sn === 0 || String(sn) === '00000000') return;

        const globalIndex = globalIndexBySlot.get(modIndex + ':' + Number(slot?.position));

        qualifyingSlots.push({
            sn,
            batteryLevel,
            globalIndex: Number.isFinite(globalIndex) ? globalIndex : -1,
            modIndex,
            moduleid: stationModule.id || modIndex,
            position: Number(slot?.position)
        });
    });
});

let candidateSlot = null;
let maxBattery = -1;
qualifyingSlots.forEach((slot) => {
    const distance = totalSlots > 0
        ? ((slot.globalIndex - vendIndex) + totalSlots) % totalSlots
        : 0;

    if (distance > 0 && slot.batteryLevel > maxBattery) {
        maxBattery = slot.batteryLevel;
        candidateSlot = slot;
    }
});

if (candidateSlot) {
    vendBatteryCandidate = candidateSlot;
    firstModuleId = candidateSlot.moduleid;
    finalSNs.push(candidateSlot.sn);
    qualifyingSlots = qualifyingSlots.filter((slot) => slot !== candidateSlot);
}

qualifyingSlots.forEach((slot) => {
    if (!vendBatteryCandidate) {
        vendBatteryCandidate = slot;
    }
    if (!firstModuleId) {
        firstModuleId = slot.moduleid;
    }
    finalSNs.push(slot.sn);
});

const statusValue = finalSNs.length === 0
    ? (recentModuleFound ? 'soldout' : 'offline')
    : finalSNs;

msg.payload = {
    stationid: station.stationid || stationId,
    moduleid: firstModuleId,
    action: 'status',
    status: statusValue,
    pricing,
    hardware,
    formoptions,
    marketingoptions,
    analyticsoptions,
    vendbattery: vendBatteryCandidate ? {
        powerlevel: vendBatteryCandidate.batteryLevel,
        slot: vendBatteryCandidate.position,
        sn: vendBatteryCandidate.sn
    } : null,
    timeresponded: now,
    timerequested: msg.payload.timerequested
};

msg.topic = 'CSTA/post/' + (station.stationid || stationId);

return msg;

function normalizeStationId(value) {
    return String(value || '').trim();
}

function toIso(value) {
    const num = Number(value);
    if (Number.isFinite(num) && num > 0) {
        const millis = String(Math.trunc(num)).length <= 10 ? num * 1000 : num;
        return new Date(millis).toISOString();
    }
    return new Date().toISOString();
}

function toMillis(value, fallback) {
    const num = Number(value);
    if (Number.isFinite(num) && num > 0) {
        return String(Math.trunc(num)).length <= 10 ? num * 1000 : num;
    }
    return fallback;
}

function firstString() {
    for (let index = 0; index < arguments.length; index++) {
        const value = String(arguments[index] ?? '').trim();
        if (value) {
            return value;
        }
    }
    return '';
}

function firstNumber() {
    for (let index = 0; index < arguments.length; index++) {
        const num = Number(arguments[index]);
        if (Number.isFinite(num)) {
            return num;
        }
    }
    return null;
}

const payload = msg.payload || {};
if (String(payload.action || '').toLowerCase() !== 'vend') {
    return null;
}

const rentalTime = toIso(payload.rentalTime || payload.timerequested || payload.time || payload.timereceived);
const requestedAtMs = toMillis(
    payload.timerequested || payload.rentalTime || payload.time || payload.timereceived,
    Date.parse(rentalTime)
);
const stationid = normalizeStationId(payload.stationid || msg.stationid || '');
const sn = firstNumber(payload.chargerid, payload.sn);
const rawid = firstString(
    payload.rawid,
    payload.transactionid,
    payload.transactionId,
    payload.rentalId,
    payload.orderid,
    payload.orderId,
    payload.paymentIntentId,
    payload.paymentintentid,
    'rent-' + (stationid || 'station') + '-' + Date.parse(rentalTime)
);
const orderid = firstString(payload.orderid, payload.orderId, rawid);

msg._pendingRentalCtx = {
    rawid,
    rentalId: firstString(payload.rentalId, orderid, rawid),
    orderid,
    transactionid: firstString(payload.transactionid, payload.transactionId),
    requestId: firstString(payload.requestId, payload.requestid, msg.requestId),
    sn,
    chargerid: sn,
    stationid,
    moduleid: firstString(payload.moduleid, payload.moduleId, payload.module, msg.moduleid),
    slotid: firstNumber(payload.slotid, payload.slot, payload.requestedSlotid),
    rentalTime,
    requestedAt: rentalTime,
    requestedAtMs,
    rentalLocation: firstString(payload.rentalLocation, msg.rentalLocation),
    rentalPlace: firstString(payload.rentalPlace, msg.rentalPlace),
    currency: firstString(payload.currency),
    symbol: firstString(payload.symbol),
    buyprice: firstNumber(payload.buyprice),
    initialCharge: firstNumber(payload.initialCharge, payload.initialcharge),
    totalCharged: firstNumber(payload.totalCharged, payload.totalcharged, payload.amountCharged),
    card_last4: firstString(payload.card_last4, payload.cardLast4, payload.last4),
    clientId: firstString(payload.clientId, payload.clientid),
    repId: firstString(payload.repId, payload.repid),
    gateway: firstString(payload.gateway),
    paymentIntentId: firstString(payload.paymentIntentId, payload.paymentintentid),
    customerId: firstString(payload.customerId, payload.customerid),
    rentPower: firstNumber(payload.rentPower, payload.rentpower, payload.powerlevel, payload.power),
    country: firstString(payload.country, payload.rentalCountry),
    memberid: firstNumber(payload.memberid, payload.memberId),
    paymentStatus: firstString(payload.paymentStatus, payload.paymentstatus),
    terminalserver: firstString(payload.terminalserver, payload.server),
    terminalsn: firstString(payload.terminalsn, payload.terminalSn),
    authorizationCode: firstString(payload.authorizationCode, payload.authorizationcode),
    overdue: firstNumber(payload.overdue),
    time: firstNumber(payload.time),
    timereceived: firstNumber(payload.timereceived)
};

if (!stationid) {
    msg.kioskDoc = null;
    return [null, msg];
}

msg.payload = {
    path: 'kiosks',
    query: [{ fieldPath: 'stationid', opStr: '==', value: stationid }]
};

return [msg, null];

function normalizeStationId(value) {
    return String(value || '').trim();
}

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const stationid = normalizeStationId(msg._pendingRentalCtx?.stationid || '');
const matched = docs.find((doc) => normalizeStationId(doc?.stationid || '') === stationid) || null;

msg.kioskDoc = matched ? JSON.parse(JSON.stringify(matched)) : null;

return msg;

function firstString() {
    for (let index = 0; index < arguments.length; index++) {
        const value = String(arguments[index] ?? '').trim();
        if (value) {
            return value;
        }
    }
    return '';
}

function isFiniteNumber(value) {
    return Number.isFinite(value);
}

function firstNumber() {
    for (let index = 0; index < arguments.length; index++) {
        const value = arguments[index];
        if (Number.isFinite(value)) {
            return value;
        }
        const parsed = Number(value);
        if (Number.isFinite(parsed)) {
            return parsed;
        }
    }
    return null;
}

function assignString(target, key) {
    const values = Array.prototype.slice.call(arguments, 2);
    const value = firstString.apply(null, values);
    if (value) {
        target[key] = value;
    }
}

function assignNumber(target, key) {
    const values = Array.prototype.slice.call(arguments, 2);
    const value = firstNumber.apply(null, values);
    if (value !== null) {
        target[key] = value;
    }
}

function normalizeRate(pricing) {
    const tiers = Array.isArray(pricing?.tiers)
        ? pricing.tiers
        : Array.isArray(pricing?.rate)
            ? pricing.rate
            : [];

    return tiers.map((tier) => ({
        time: Number(tier?.time ?? 0),
        price: Number(tier?.price ?? 0)
    }));
}

const ctx = msg._pendingRentalCtx;
if (!ctx) {
    node.error('Missing msg._pendingRentalCtx', msg);
    return null;
}

const kiosk = msg.kioskDoc || {};
const info = kiosk.info && typeof kiosk.info === 'object' ? kiosk.info : {};
const pricing = kiosk.pricing && typeof kiosk.pricing === 'object' ? kiosk.pricing : {};
const hardware = kiosk.hardware && typeof kiosk.hardware === 'object' ? kiosk.hardware : {};

const pricingAtStart = {
    kioskmode: pricing.kioskmode || null,
    buyprice: firstNumber(ctx.buyprice, pricing.buyprice) ?? 0,
    overdue: firstNumber(ctx.overdue, pricing.overdue) ?? 0,
    currency: firstString(ctx.currency, pricing.currency) || null,
    symbol: firstString(ctx.symbol, pricing.symbol) || null,
    taxrate: firstNumber(pricing.taxrate, pricing.taxpercent) ?? 0,
    rate: normalizeRate(pricing),
    snapshotAt: new Date().toISOString()
};

const rentalTimeMs = Date.parse(ctx.rentalTime);
const overdueDays = Number(pricingAtStart.overdue || 0);
const overdueTime = Number.isFinite(rentalTimeMs)
    ? new Date(rentalTimeMs + overdueDays * 24 * 60 * 60 * 1000).toISOString()
    : ctx.rentalTime;

const rentalDoc = {
    rawid: ctx.rawid,
    rentalId: firstString(ctx.rentalId, ctx.orderid, ctx.rawid),
    orderid: ctx.orderid,
    status: 'pending',
    rentalStationid: firstString(ctx.stationid, kiosk.stationid),
    rentalTime: ctx.rentalTime,
    requestedAt: ctx.requestedAt,
    overdueTime,
    overdue: pricingAtStart.overdue,
    buyprice: pricingAtStart.buyprice,
    currency: pricingAtStart.currency,
    symbol: pricingAtStart.symbol,
    pricingAtStart,
    kioskDocId: firstString(kiosk.provisionid, kiosk.stationid)
};

assignNumber(rentalDoc, 'sn', ctx.sn);
assignNumber(rentalDoc, 'chargerid', ctx.chargerid);
assignString(rentalDoc, 'rentalModuleid', ctx.moduleid);
assignString(rentalDoc, 'requestId', ctx.requestId);
assignString(rentalDoc, 'rentalLocation', ctx.rentalLocation, info.location);
assignString(rentalDoc, 'rentalPlace', ctx.rentalPlace, info.place);
assignString(rentalDoc, 'card_last4', ctx.card_last4);
assignString(rentalDoc, 'clientId', ctx.clientId, info.clientId, info.client);
assignString(rentalDoc, 'repId', ctx.repId, info.rep);
assignString(rentalDoc, 'gateway', ctx.gateway, hardware.gateway);
assignString(rentalDoc, 'paymentIntentId', ctx.paymentIntentId);
assignString(rentalDoc, 'customerId', ctx.customerId);
assignString(rentalDoc, 'country', ctx.country, info.country);
assignNumber(rentalDoc, 'memberid', ctx.memberid);

if (ctx.transactionid) {
    rentalDoc.transactionid = ctx.transactionid;
}

if (ctx.paymentStatus) {
    rentalDoc.paymentStatus = ctx.paymentStatus;
}

if (ctx.terminalserver) {
    rentalDoc.terminalserver = ctx.terminalserver;
}

if (ctx.terminalsn) {
    rentalDoc.terminalsn = ctx.terminalsn;
}

if (ctx.authorizationCode) {
    rentalDoc.authorizationCode = ctx.authorizationCode;
}

if (ctx.slotid !== null) {
    rentalDoc.rentalSlotid = ctx.slotid;
    rentalDoc.requestedSlotid = ctx.slotid;
}

if (ctx.requestedAtMs) {
    rentalDoc.timerequested = ctx.requestedAtMs;
}

assignNumber(rentalDoc, 'initialCharge', ctx.initialCharge);
assignNumber(rentalDoc, 'rentPower', ctx.rentPower);
assignNumber(rentalDoc, 'time', ctx.time);
assignNumber(rentalDoc, 'timereceived', ctx.timereceived);

if (ctx.totalCharged !== null) {
    rentalDoc.totalCharged = ctx.totalCharged;
}

msg.payload = {
    path: 'rentals/' + ctx.orderid,
    content: rentalDoc
};

return msg;

const requestData = msg.payload && typeof msg.payload === 'object' && !Array.isArray(msg.payload)
    ? msg.payload
    : {};
const queryData = msg.req && msg.req.query && typeof msg.req.query === 'object'
    ? msg.req.query
    : {};

const rawUuid = String(requestData.uuid || queryData.uuid || '').trim();
const rawStationId = String(
    requestData.stationid ||
    requestData.stationId ||
    queryData.stationid ||
    queryData.stationId ||
    ''
).trim();

function buildModuleCandidates(value) {
    const normalized = String(value || '').trim();
    const candidates = new Set();

    if (!normalized) {
        return [];
    }

    candidates.add(normalized);

    if (normalized.startsWith('1000')) {
        candidates.add(normalized.replace(/^1000/, ''));
    } else {
        candidates.add('1000' + normalized);
    }

    if (/^(?:[0-9A-Fa-f]{2}[:-]){5}[0-9A-Fa-f]{2}$/.test(normalized)) {
        const hex = normalized.replace(/[:-]/g, '');
        const decimalValue = String(Number.parseInt(hex, 16));
        candidates.add(decimalValue);
        candidates.add('1000' + decimalValue);
    }

    return Array.from(candidates).filter(Boolean);
}

if (!rawUuid && !rawStationId) {
    msg.payload = {
        code: 400,
        type: 0,
        data: [],
        msg: 'Missing uuid',
        time: Date.now()
    };
    return [null, msg];
}

msg._mediaLookup = {
    rawUuid,
    stationid: rawStationId,
    moduleCandidates: buildModuleCandidates(rawUuid)
};

msg.payload = rawStationId
    ? {
        path: 'kiosks',
        query: [{ fieldPath: 'stationid', opStr: '==', value: rawStationId }]
    }
    : {
        path: 'kiosks',
        query: []
    };

return [msg, null];

const ALLOW_PDF = false;

function moduleMatches(moduleId, candidates) {
    const normalized = String(moduleId || '').trim();
    if (!normalized || !Array.isArray(candidates) || candidates.length === 0) {
        return false;
    }

    if (candidates.includes(normalized)) {
        return true;
    }

    if (normalized.startsWith('1000') && candidates.includes(normalized.replace(/^1000/, ''))) {
        return true;
    }

    return candidates.includes('1000' + normalized);
}

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const lookup = msg._mediaLookup && typeof msg._mediaLookup === 'object' ? msg._mediaLookup : {};
const moduleId = String(lookup.rawUuid || '').trim();
const requestedStationId = String(lookup.stationid || '').trim();
const moduleCandidates = Array.isArray(lookup.moduleCandidates) ? lookup.moduleCandidates : [];

let matchedStation = null;

if (requestedStationId) {
    matchedStation = docs.find((doc) => String(doc && doc.stationid || '').trim() === requestedStationId) || null;
}

if (!matchedStation && moduleCandidates.length > 0) {
    matchedStation = docs.find((doc) => {
        const modules = Array.isArray(doc && doc.modules) ? doc.modules : [];
        return modules.some((module) => moduleMatches(module && module.id, moduleCandidates));
    }) || null;
}

if (!matchedStation) {
    msg.payload = {
        code: 404,
        type: 0,
        data: [],
        msg: 'No matching station for uuid',
        time: Date.now()
    };
    return msg;
}

const media = matchedStation.media && typeof matchedStation.media === 'object' ? matchedStation.media : {};
const rawPlaylist = Array.isArray(media.playlist) ? media.playlist : [];
const screenBrightnessValue = Number(media.screenBrightness ?? 255);
const screenBrightness = Number.isFinite(screenBrightnessValue) ? screenBrightnessValue : 255;
const defaultPlayTimeValue = Number(media.playTime ?? 20);
const defaultPlayTime = Number.isFinite(defaultPlayTimeValue) ? defaultPlayTimeValue : 20;

const playlist = rawPlaylist
    .filter((item) => item && typeof item.downloadUrl === 'string' && item.downloadUrl.trim())
    .filter((item) => {
        const contentType = String(item.contentType || '').trim().toLowerCase();
        if (!ALLOW_PDF && contentType === 'application/pdf') {
            return false;
        }
        return true;
    })
    .sort((left, right) => Number(left.order || 0) - Number(right.order || 0))
    .map((item, index) => ({
        guuid: moduleId || String(moduleCandidates[0] || ''),
        url1: '',
        url2: item.downloadUrl.trim(),
        url3: '',
        forward: '',
        screenBrightness,
        weight: Number(item.weight ?? 0),
        playTime: Number(item.playTime ?? defaultPlayTime),
        id: Number(item.id ?? (100001 + index)),
        title: String(item.name || item.title || ''),
        fileType: Number(item.fileType ?? 0)
    }));

if (media.active !== true || playlist.length === 0) {
    const filteredPdfCount = rawPlaylist.filter((item) => (
        String(item && item.contentType || '').trim().toLowerCase() === 'application/pdf'
    )).length;

    msg.payload = {
        code: 200,
        type: 0,
        data: [],
        msg: !ALLOW_PDF && filteredPdfCount > 0 ? 'No supported media assigned' : 'No media assigned',
        time: Date.now()
    };
    return msg;
}

msg.payload = {
    code: 200,
    type: 0,
    data: playlist,
    msg: 'OK',
    time: Date.now()
};

return msg;
